11818	\begin{lemma}
11819	[A finite product of right-\(f_*\)-acyclic objects is right-\(f_*\)-acyclic]
11820	  \label{lem:rightAcyclic_finite_prod}
11821	  \lean{AlgebraicGeometry.rightAcyclic_finite_prod}
11822	  \textit{Project-local.}
11823	  Let \(G : \mathcal{A} \to \mathcal{B}\) be an additive functor between abelian
11824	  categories that admits a right-derived functor, and let \((X_s)_{s \in \Sigma}\)
11825	  be a \emph{finite} family of objects of \(\mathcal{A}\), each right
11826	  \(G\)-acyclic --- \(G.\mathrm{rightDerived}\,k\,(X_s) = 0\) for all \(k \geq 1\)
11827	  and all \(s\). Then the product \(\prod_{s \in \Sigma} X_s\) is right
11828	  \(G\)-acyclic: \(G.\mathrm{rightDerived}\,k\,\bigl(\prod_s X_s\bigr) = 0\) for all
11829	  \(k \geq 1\).
11830	\end{lemma}
11831	\begin{proof}
11832	  A finite product in an abelian category is a finite biproduct, and an additive
11833	  right-derived functor preserves finite biproducts; hence for every \(k\) there is
11834	  an isomorphism
11835	  \[
11836	    G.\mathrm{rightDerived}\,k\,\Bigl(\prod_{s} X_s\Bigr)
11837	      \;\cong\;
11838	    \prod_{s} G.\mathrm{rightDerived}\,k\,(X_s).
11839	  \]
11840	  For \(k \geq 1\) each factor on the right vanishes by the acyclicity hypothesis, so
11841	  the product vanishes, and the isomorphism forces the left-hand side to vanish as well.
11842	\end{proof}
